mapper.select:
SELECT COUNT(*) FROM project
                WHERE title = #{title}
                AND status = 'K1'

SELECT COUNT(*) FROM project
                WHERE identifier = #{identifier}
                AND status = 'K1'

SELECT COUNT(*) FROM project
WHERE identifier = #{identifier}
  AND status = 'K1'
  AND id != #{projectId}

SELECT COUNT(*) FROM project
WHERE title = #{title}
  AND status = 'K1'
  AND id != #{projectId}

SELECT p.id, p.title, p.user_id AS pmId, u.name AS pmName, p.end_date AS endDate, p.is_lock AS isLock FROM project p LEFT JOIN users u ON u.id = p.user_id WHERE p.status = 'K1'
AND p.id = #{id}
AND p.user_id = #{pmId}
AND p.end_date >= #{startDate}
AND p.end_date <= #{endDate}
AND p.is_lock = 'L0'
ORDER BY p.id DESC

mapper.update:
UPDATE project
SET is_lock = 'L1'
WHERE id = #{id}

UPDATE project
SET is_lock = 'L0'
WHERE id = #{id}

UPDATE project
SET status = 'K0'
WHERE id = #{id}

mapper.select:
SELECT default_version_id
FROM project
WHERE id = #{projectId}

mapper.update:
UPDATE project
SET default_version_id = #{versionId}
WHERE id = #{projectId}

